import{c as s,Q as n,j as t,m as e}from"./chunks/framework.Bhbi9jCp.js";const u=JSON.parse('{"title":"权限模型:相机、相册、定位、麦克风、通知","description":"","frontmatter":{},"headers":[],"relativePath":"mobileCommonLearning/12-权限模型.md","filePath":"mobileCommonLearning/12-权限模型.md","lastUpdated":1780912084000}'),i={name:"mobileCommonLearning/12-权限模型.md"};function l(p,a,d,o,r,c){return n(),t("div",null,[...a[0]||(a[0]=[e(`<h1 id="权限模型-相机、相册、定位、麦克风、通知" tabindex="-1">权限模型:相机、相册、定位、麦克风、通知 <a class="header-anchor" href="#权限模型-相机、相册、定位、麦克风、通知" aria-label="Permalink to &quot;权限模型:相机、相册、定位、麦克风、通知&quot;">​</a></h1><p>权限不是弹窗。权限是用户把某种设备能力临时授权给你的应用。</p><p>一句话先记住:<strong>权限要在用户触发具体功能时申请,并且要能处理拒绝、限制和系统设置变更。</strong></p><hr><h2 id="一、常见权限" tabindex="-1">一、常见权限 <a class="header-anchor" href="#一、常见权限" aria-label="Permalink to &quot;一、常见权限&quot;">​</a></h2><table tabindex="0"><thead><tr><th>能力</th><th>常见用途</th></tr></thead><tbody><tr><td>相机</td><td>拍照、扫码、视频</td></tr><tr><td>相册 / 媒体</td><td>选择图片、保存文件</td></tr><tr><td>定位</td><td>地图、附近、打卡</td></tr><tr><td>麦克风</td><td>语音、通话、录音</td></tr><tr><td>通知</td><td>消息提醒、营销、系统事件</td></tr><tr><td>蓝牙</td><td>设备连接</td></tr><tr><td>联系人</td><td>邀请、通讯录</td></tr><tr><td>日历</td><td>日程</td></tr></tbody></table><p>原则:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>不用就不申请</span></span>
<span class="line"><span>用到再申请</span></span>
<span class="line"><span>拒绝要能继续走替代流程</span></span></code></pre></div><hr><h2 id="二、权限状态" tabindex="-1">二、权限状态 <a class="header-anchor" href="#二、权限状态" aria-label="Permalink to &quot;二、权限状态&quot;">​</a></h2><p>不要只判断&quot;有 / 没有&quot;。</p><p>常见状态:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>notDetermined  用户还没决定</span></span>
<span class="line"><span>granted        已授权</span></span>
<span class="line"><span>denied         拒绝</span></span>
<span class="line"><span>restricted     系统或家长控制限制</span></span>
<span class="line"><span>limited        只允许部分资源(iOS 相册)</span></span>
<span class="line"><span>permanentlyDenied  拒绝且不再弹窗(Android 常见)</span></span></code></pre></div><p>UI 要根据状态分支。</p><hr><h2 id="三、申请时机" tabindex="-1">三、申请时机 <a class="header-anchor" href="#三、申请时机" aria-label="Permalink to &quot;三、申请时机&quot;">​</a></h2><p>坏:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>App 启动 -&gt; 连续弹相机、定位、通知</span></span></code></pre></div><p>好:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>用户点击&quot;拍照上传&quot;</span></span>
<span class="line"><span>  -&gt; 解释为什么需要相机</span></span>
<span class="line"><span>  -&gt; 申请相机权限</span></span>
<span class="line"><span>  -&gt; 成功后打开相机</span></span></code></pre></div><p>权限弹窗前最好有业务上下文。</p><hr><h2 id="四、拒绝后的流程" tabindex="-1">四、拒绝后的流程 <a class="header-anchor" href="#四、拒绝后的流程" aria-label="Permalink to &quot;四、拒绝后的流程&quot;">​</a></h2><p>用户拒绝后:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>展示原因</span></span>
<span class="line"><span>提供设置入口</span></span>
<span class="line"><span>提供替代方案</span></span>
<span class="line"><span>不要无限弹窗</span></span></code></pre></div><p>例如相册:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>你可以继续填写表单</span></span>
<span class="line"><span>也可以去设置中允许相册权限后上传图片</span></span></code></pre></div><p>拒绝权限不应该让整个 App 死掉。</p><hr><h2 id="五、android-特点" tabindex="-1">五、Android 特点 <a class="header-anchor" href="#五、android-特点" aria-label="Permalink to &quot;五、Android 特点&quot;">​</a></h2><p>Android 重点:</p><ul><li>运行时权限</li><li>target SDK 影响权限行为</li><li>通知权限在新系统上需要显式申请</li><li>后台定位比前台定位更严格</li><li>相册 / 媒体权限随系统版本演进</li><li><code>shouldShowRequestPermissionRationale</code> 判断是否展示解释</li></ul><p>不要只按一台测试机判断权限逻辑。</p><hr><h2 id="六、ios-特点" tabindex="-1">六、iOS 特点 <a class="header-anchor" href="#六、ios-特点" aria-label="Permalink to &quot;六、iOS 特点&quot;">​</a></h2><p>iOS 重点:</p><ul><li><code>Info.plist</code> 必须写用途说明</li><li>相册有 limited access</li><li>定位分 When In Use / Always</li><li>通知授权独立</li><li>权限被拒后通常要引导用户去 Settings</li><li>隐私能力和 App Review 强相关</li></ul><p>用途文案必须具体,不要写模板废话。</p><hr><h2 id="七、flutter-rn" tabindex="-1">七、Flutter / RN <a class="header-anchor" href="#七、flutter-rn" aria-label="Permalink to &quot;七、Flutter / RN&quot;">​</a></h2><p>跨端框架只封装 API,不消除平台差异。</p><p>你仍然要配置:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>AndroidManifest.xml</span></span>
<span class="line"><span>Info.plist</span></span>
<span class="line"><span>Gradle / Pod 依赖</span></span>
<span class="line"><span>运行时申请</span></span>
<span class="line"><span>平台差异分支</span></span></code></pre></div><p>权限库不能替你决定业务流程。</p><hr><h2 id="八、什么时候会出事故" tabindex="-1">八、什么时候会出事故 <a class="header-anchor" href="#八、什么时候会出事故" aria-label="Permalink to &quot;八、什么时候会出事故&quot;">​</a></h2><ol><li>iOS <code>Info.plist</code> 缺用途说明,直接崩或拒审。</li><li>Android target SDK 升级后权限行为变化。</li><li>用户拒绝权限后页面卡死。</li><li>相册 limited 模式下以为拿到了全部照片。</li><li>后台定位没有合规说明,被拒审。</li><li>通知没申请成功,运营以为推送系统坏了。</li></ol><hr><h2 id="九、检查清单" tabindex="-1">九、检查清单 <a class="header-anchor" href="#九、检查清单" aria-label="Permalink to &quot;九、检查清单&quot;">​</a></h2><ul><li>[ ] 是否只在功能触发时申请权限</li><li>[ ] 是否处理 denied / limited / restricted</li><li>[ ] 是否有设置页引导</li><li>[ ] 是否有替代流程</li><li>[ ] iOS <code>Info.plist</code> 文案是否具体</li><li>[ ] Android target SDK 升级后是否重测权限</li><li>[ ] 权限用途是否写进隐私政策</li><li>[ ] 真机是否覆盖主流系统版本</li></ul><hr><h2 id="十、心智模型" tabindex="-1">十、心智模型 <a class="header-anchor" href="#十、心智模型" aria-label="Permalink to &quot;十、心智模型&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>权限是用户授权,不是开发者配置</span></span>
<span class="line"><span>用途说明影响审核和信任</span></span>
<span class="line"><span>拒绝权限是正常路径</span></span>
<span class="line"><span>系统版本会改变权限行为</span></span>
<span class="line"><span>跨端框架不屏蔽平台规则</span></span></code></pre></div><p>下一篇 13 讲推送通知。</p>`,54)])])}const b=s(i,[["render",l]]);export{u as __pageData,b as default};
